INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Metric units</b>: length (mm, cm, m, km), mass (g, kg, t), capacity (ml, cl, l).<br>• $1\\text{ km} = 1000\\text{ m}$, $1\\text{ m} = 100\\text{ cm}$, $1\\text{ cm} = 10\\text{ mm}$.<br>• $1\\text{ kg} = 1000\\text{ g}$, $1\\text{ tonne} = 1000\\text{ kg}$, $1\\text{ litre} = 1000\\text{ ml} = 1000\\text{ cm}^3$.<br><br><b>Key Skills</b><br>• Convert between units: multiply to go smaller → larger count, divide to go larger → smaller count.<br>• <b>Area conversions</b>: $1\\text{ m}^2 = 10\\,000\\text{ cm}^2$ (multiply factor <b>squared</b>).<br>• <b>Volume conversions</b>: $1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$ (multiply factor <b>cubed</b>).<br>• <b>Compound measures</b>: speed $= \\frac{d}{t}$, density $= \\frac{m}{V}$, population density $= \\frac{\\text{population}}{\\text{area}}$.<br><br><b>Watch Out!</b><br>When converting area or volume, apply the conversion factor twice (area) or three times (volume). E.g. $2\\text{ m}^2 = 2 \\times 10\\,000 = 20\\,000\\text{ cm}^2$.","content_zh":"<b>知识回顾</b><br>• <b>公制单位</b>：长度 (mm, cm, m, km)，质量 (g, kg, t)，容量 (ml, cl, l)。<br>• $1\\text{ km} = 1000\\text{ m}$, $1\\text{ m} = 100\\text{ cm}$, $1\\text{ cm} = 10\\text{ mm}$。<br>• $1\\text{ kg} = 1000\\text{ g}$, $1\\text{ tonne} = 1000\\text{ kg}$, $1\\text{ litre} = 1000\\text{ ml} = 1000\\text{ cm}^3$。<br><br><b>关键技能</b><br>• 单位换算：换算为更小单位时用乘法 → 数值变大；换算为更大单位时用除法 → 数值变小。<br>• <b>面积换算</b>：$1\\text{ m}^2 = 10\\,000\\text{ cm}^2$（乘换算因子的<b>平方</b>）。<br>• <b>体积换算</b>：$1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$（乘换算因子的<b>立方</b>）。<br>• <b>复合度量</b>：速度 $= \\frac{d}{t}$，密度 $= \\frac{m}{V}$，人口密度 $= \\frac{\\text{population}}{\\text{area}}$。<br><br><b>注意！</b><br>进行面积或体积换算时，需应用两次（面积）或三次（体积）换算因子。例如：$2\\text{ m}^2 = 2 \\times 10\\,000 = 20\\,000\\text{ cm}^2$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Convert $3.5\\text{ m}^2$ to $\\text{cm}^2$.<br><br><b>Solution:</b><br>$1\\text{ m} = 100\\text{ cm}$, so $1\\text{ m}^2 = 100^2 = 10\\,000\\text{ cm}^2$.<br>$3.5 \\times 10\\,000 = 35\\,000\\text{ cm}^2$<br><br><b>Worked Example 2</b> [3 marks]<br>A block of metal has mass 540 g and volume $200\\text{ cm}^3$. Find the density in g/cm$^3$. Another block of the same metal has volume $350\\text{ cm}^3$. Find its mass.<br><br><b>Solution:</b><br>Density $= \\frac{540}{200} = 2.7\\text{ g/cm}^3$<br>Mass $= 2.7 \\times 350 = 945$ g<br><br><b>Worked Example 3</b> [3 marks]<br>A car travels 150 km in 2 hours 30 minutes. Calculate its average speed in km/h and convert it to m/s.<br><br><b>Solution:</b><br>Time $= 2.5$ hours<br>Speed $= \\frac{150}{2.5} = 60\\text{ km/h}$<br>Convert: $60 \\times \\frac{1000}{3600} = 60 \\times \\frac{5}{18} = \\frac{300}{18} = 16.7\\text{ m/s}$<br><br><b>Worked Example 4</b> [3 marks]<br>Convert $0.5\\text{ m}^3$ to litres.<br><br><b>Solution:</b><br>$1\\text{ m}^3 = 100^3 = 1\\,000\\,000\\text{ cm}^3$<br>$0.5\\text{ m}^3 = 0.5 \\times 1\\,000\\,000 = 500\\,000\\text{ cm}^3$<br>$1\\text{ litre} = 1000\\text{ cm}^3$, so $500\\,000 \\div 1000 = 500$ litres<br><br><b>Exam Tip:</b> For area conversions, square the factor; for volume, cube it. Always show the conversion factor clearly.","content_zh":"<b>经典例题 1</b> [2 分]<br>将 $3.5\\text{ m}^2$ 换算为 cm$^2$。<br><br><b>解答：</b><br>$1\\text{ m} = 100\\text{ cm}$，所以 $1\\text{ m}^2 = 100^2 = 10\\,000\\text{ cm}^2$。<br>$3.5 \\times 10\\,000 = 35\\,000\\text{ cm}^2$<br><br><b>经典例题 2</b> [3 分]<br>金属块质量 540 g，体积 $200\\text{ cm}^3$。另一块同材料体积 $350\\text{ cm}^3$，求质量。<br><br><b>解答：</b><br>密度 $= \\frac{540}{200} = 2.7\\text{ g/cm}^3$<br>质量 $= 2.7 \\times 350 = 945$ g<br><br><b>经典例题 3</b> [3 分]<br>一辆汽车 2 小时 30 分钟行驶了 150 km。计算其平均速度（km/h），并换算为 m/s。<br><br><b>解答：</b><br>时间 $= 2.5$ 小时<br>速度 $= \\frac{150}{2.5} = 60\\text{ km/h}$<br>换算：$60 \\times \\frac{1000}{3600} = 16.7\\text{ m/s}$<br><br><b>经典例题 4</b> [3 分]<br>将 $0.5\\text{ m}^3$ 换算为升。<br><br><b>解答：</b><br>$1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$<br>$0.5\\text{ m}^3 = 500\\,000\\text{ cm}^3$<br>$1\\text{ litre} = 1000\\text{ cm}^3$，所以 $500\\,000 \\div 1000 = 500$ 升<br><br><b>考试技巧：</b>面积换算需将因子平方，体积换算需将因子立方。务必清晰写出换算因子。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Rectangle</b>: $A = lw$, $P = 2(l+w)$.<br>• <b>Triangle</b>: $A = \\frac{1}{2}bh$ (perpendicular height).<br>• <b>Parallelogram</b>: $A = bh$.<br>• <b>Trapezium</b>: $A = \\frac{1}{2}(a+b)h$.<br>• <b>Kite</b>: $A = \\frac{1}{2}d_1 d_2$ (diagonals).<br><br><b>Key Skills</b><br>• Break compound shapes into simpler shapes.<br>• Find shaded area by subtraction: whole shape minus removed part.<br>• Use $A = \\frac{1}{2}ab\\sin C$ for non-right-angled triangles (Extended).<br><br><b>Exam Tip</b><br>Always check you are using the <b>perpendicular</b> height, not a slant side.","content_zh":"<b>知识回顾</b><br>• <b>长方形</b>：$A = lw$，$P = 2(l+w)$。<br>• <b>三角形</b>：$A = \\frac{1}{2}bh$（垂直高度）。<br>• <b>平行四边形</b>：$A = bh$。<br>• <b>梯形</b>：$A = \\frac{1}{2}(a+b)h$。<br>• <b>筝形</b>：$A = \\frac{1}{2}d_1 d_2$（对角线）。<br><br><b>关键技能</b><br>• 将复合图形分解为更简单的图形。<br>• 通过减法求阴影部分面积：整体图形减去扣除部分。<br>• 对于非直角三角形，使用 $A = \\frac{1}{2}ab\\sin C$（进阶部分）。<br><br><b>考试技巧</b><br>务必检查你使用的是<b>垂直</b>高度，而非斜边。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.2', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>A rectangle has length 12 cm and width 5 cm. Calculate its area and perimeter.<br><br><b>Solution:</b><br>Area $= 12 \\times 5 = 60\\text{ cm}^2$<br>Perimeter $= 2(12 + 5) = 2 \\times 17 = 34$ cm<br><br><b>Worked Example 2</b> [3 marks]<br>A trapezium has parallel sides 8 cm and 14 cm and perpendicular height 6 cm. Calculate its area.<br><br><b>Solution:</b><br>$A = \\frac{1}{2}(8 + 14) \\times 6 = \\frac{1}{2} \\times 22 \\times 6 = 66\\text{ cm}^2$<br><br><b>Worked Example 3</b> [4 marks]<br>A parallelogram has base 15 cm. Its area is $120\\text{ cm}^2$. Find its perpendicular height. A triangle is cut from the parallelogram with the same base and height. Find the area of the triangle.<br><br><b>Solution:</b><br>Parallelogram: $A = bh$, so $120 = 15h$, $h = 8$ cm.<br>Triangle: $A = \\frac{1}{2} \\times 15 \\times 8 = 60\\text{ cm}^2$<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>Triangle $PQR$: $PQ = 9$ cm, $PR = 7$ cm, $\\angle P = 48°$. Find the area.<br><br><b>Solution:</b><br>$A = \\frac{1}{2} \\times 9 \\times 7 \\times \\sin 48°$<br>$= 31.5 \\times 0.7431 = 23.4\\text{ cm}^2$<br><br><b>Exam Tip:</b> Always check you are using the perpendicular height, not a slant side. For non-right-angled triangles (Extended), use $A = \\frac{1}{2}ab\\sin C$.","content_zh":"<b>经典例题 1</b> [2 分]<br>长方形长 12 cm，宽 5 cm。计算其面积和周长。<br><br><b>解答：</b><br>面积 $= 12 \\times 5 = 60\\text{ cm}^2$<br>周长 $= 2(12 + 5) = 34$ cm<br><br><b>经典例题 2</b> [3 分]<br>梯形平行边 8 cm 和 14 cm，高 6 cm，求面积。<br><br><b>解答：</b><br>$A = \\frac{1}{2}(8 + 14) \\times 6 = \\frac{1}{2} \\times 22 \\times 6 = 66\\text{ cm}^2$<br><br><b>经典例题 3</b> [4 分]<br>平行四边形底边 15 cm，面积 $120\\text{ cm}^2$。求垂直高度。从该平行四边形中切出一个同底同高的三角形，求三角形面积。<br><br><b>解答：</b><br>平行四边形：$A = bh$，$120 = 15h$，$h = 8$ cm。<br>三角形：$A = \\frac{1}{2} \\times 15 \\times 8 = 60\\text{ cm}^2$<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>$PQ = 9$ cm，$PR = 7$ cm，$\\angle P = 48°$。求面积。<br><br><b>解答：</b><br>$A = \\frac{1}{2} \\times 9 \\times 7 \\times \\sin 48° = 31.5 \\times 0.7431 = 23.4\\text{ cm}^2$<br><br><b>考试技巧：</b>务必使用垂直高度而非斜边。对于非直角三角形（进阶），使用 $A = \\frac{1}{2}ab\\sin C$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Circle</b>: circumference $C = 2\\pi r = \\pi d$, area $A = \\pi r^2$.<br>• <b>Arc length</b> $= \\frac{\\theta}{360} \\times 2\\pi r$.<br>• <b>Sector area</b> $= \\frac{\\theta}{360} \\times \\pi r^2$.<br>• <b>Perimeter of sector</b> $=$ arc length $+ 2r$.<br><br><b>Key Skills</b><br>• Find arc length and sector area given angle and radius.<br>• Find the angle given the arc or area.<br>• Find the radius given the area or circumference.<br><br><b>Watch Out!</b><br>Perimeter of a sector is NOT just the arc. You must add the two radii: $P = \\frac{\\theta}{360} \\times 2\\pi r + 2r$.","content_zh":"<b>知识回顾</b><br>• <b>圆</b>：周长 $C = 2\\pi r = \\pi d$，面积 $A = \\pi r^2$。<br>• <b>弧长</b> $= \\frac{\\theta}{360} \\times 2\\pi r$。<br>• <b>扇形面积</b> $= \\frac{\\theta}{360} \\times \\pi r^2$。<br>• <b>扇形周长</b> $=$ 弧长 $+ 2r$。<br><br><b>关键技能</b><br>• 已知角度和半径，求弧长和扇形面积。<br>• 已知弧长或面积，求角度。<br>• 已知面积或周长，求半径。<br><br><b>注意！</b><br>扇形的周长不仅是弧长。你必须加上两条半径：$P = \\frac{\\theta}{360} \\times 2\\pi r + 2r$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.3', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>A circle has radius 7 cm. Find its circumference and area.<br><br><b>Solution:</b><br>Circumference $= 2\\pi \\times 7 = 14\\pi = 44.0$ cm<br>Area $= \\pi \\times 7^2 = 49\\pi = 153.9\\text{ cm}^2$<br><br><b>Worked Example 2</b> [3 marks]<br>The area of a circle is $200\\text{ cm}^2$. Find its radius and circumference.<br><br><b>Solution:</b><br>$\\pi r^2 = 200$<br>$r^2 = \\frac{200}{\\pi} = 63.66...$<br>$r = \\sqrt{63.66} = 7.98$ cm<br>Circumference $= 2\\pi \\times 7.98 = 50.1$ cm<br><br><b>Worked Example 3</b> [4 marks]<br>A sector has radius 12 cm and angle $150°$. Find (a) the arc length, (b) the area, (c) the perimeter.<br><br><b>Solution:</b><br>(a) Arc $= \\frac{150}{360} \\times 2\\pi \\times 12 = \\frac{5}{12} \\times 24\\pi = 10\\pi = 31.4$ cm<br>(b) Area $= \\frac{150}{360} \\times \\pi \\times 144 = 60\\pi = 188.5\\text{ cm}^2$<br>(c) Perimeter $= 31.4 + 2(12) = 31.4 + 24 = 55.4$ cm<br><br><b>Worked Example 4</b> [4 marks]<br>A sector has area $75\\text{ cm}^2$ and radius 10 cm. Find the angle at the centre and the arc length.<br><br><b>Solution:</b><br>$\\frac{\\theta}{360} \\times \\pi \\times 10^2 = 75$<br>$\\frac{\\theta}{360} \\times 100\\pi = 75$<br>$\\frac{\\theta}{360} = \\frac{75}{100\\pi} = 0.2387...$<br>$\\theta = 0.2387 \\times 360 = 85.9°$<br>Arc length $= \\frac{85.9}{360} \\times 2\\pi \\times 10 = 15.0$ cm<br><br><b>Exam Tip:</b> The perimeter of a sector is NOT just the arc length — remember to add the two radii: $P = \\text{arc} + 2r$.","content_zh":"<b>经典例题 1</b> [2 分]<br>圆的半径为 7 cm。求其周长和面积。<br><br><b>解答：</b><br>周长 $= 2\\pi \\times 7 = 14\\pi = 44.0$ cm<br>面积 $= \\pi \\times 7^2 = 49\\pi = 153.9\\text{ cm}^2$<br><br><b>经典例题 2</b> [3 分]<br>一个圆的面积为 $200\\text{ cm}^2$。求其半径和周长。<br><br><b>解答：</b><br>$\\pi r^2 = 200$，$r^2 = \\frac{200}{\\pi} = 63.66$，$r = 7.98$ cm<br>周长 $= 2\\pi \\times 7.98 = 50.1$ cm<br><br><b>经典例题 3</b> [4 分]<br>扇形半径 12 cm，角 $150°$。求弧长、面积、周长。<br><br><b>解答：</b><br>(a) 弧长 $= \\frac{150}{360} \\times 2\\pi \\times 12 = 10\\pi = 31.4$ cm<br>(b) 面积 $= \\frac{150}{360} \\times \\pi \\times 144 = 60\\pi = 188.5\\text{ cm}^2$<br>(c) 周长 $= 31.4 + 24 = 55.4$ cm<br><br><b>经典例题 4</b> [4 分]<br>一个扇形的面积为 $75\\text{ cm}^2$，半径为 10 cm。求圆心角和弧长。<br><br><b>解答：</b><br>$\\frac{\\theta}{360} \\times \\pi \\times 10^2 = 75$<br>$\\frac{\\theta}{360} = \\frac{75}{100\\pi} = 0.2387$<br>$\\theta = 85.9°$<br>弧长 $= \\frac{85.9}{360} \\times 2\\pi \\times 10 = 15.0$ cm<br><br><b>考试技巧：</b>扇形的周长不仅仅是弧长 —— 别忘了加上两条半径：$P = \\text{弧长} + 2r$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Cuboid</b>: $V = lwh$, SA $= 2(lw + lh + wh)$.<br>• <b>Prism</b>: $V = \\text{cross-section} \\times \\text{length}$.<br>• <b>Cylinder</b>: $V = \\pi r^2 h$, curved SA $= 2\\pi rh$, total SA $= 2\\pi rh + 2\\pi r^2$.<br>• <b>Cone</b>: $V = \\frac{1}{3}\\pi r^2 h$, curved SA $= \\pi rl$ ($l$ = slant height, $l^2 = r^2 + h^2$).<br>• <b>Sphere</b>: $V = \\frac{4}{3}\\pi r^3$, SA $= 4\\pi r^2$.<br>• <b>Pyramid</b>: $V = \\frac{1}{3} \\times \\text{base area} \\times h$.<br><br><b>Key Skills</b><br>• Find volume and surface area of compound solids (e.g. hemisphere on cylinder).<br>• Find missing dimensions given volume or surface area.<br>• Use Pythagoras to find slant height of a cone.<br><br><b>Exam Tip</b><br>Formulae for cone, sphere, and pyramid are given on the formula sheet — but practise using them.","content_zh":"<b>知识回顾</b><br>• <b>长方体</b>：$V = lwh$，SA $= 2(lw + lh + wh)$。<br>• <b>棱柱</b>：$V = \\text{cross-section} \\times \\text{length}$。<br>• <b>圆柱体</b>：$V = \\pi r^2 h$，侧面积 $= 2\\pi rh$，总表面积 $= 2\\pi rh + 2\\pi r^2$。<br>• <b>圆锥体</b>：$V = \\frac{1}{3}\\pi r^2 h$，侧面积 $= \\pi rl$（$l$ = 斜高, $l^2 = r^2 + h^2$）。<br>• <b>球体</b>：$V = \\frac{4}{3}\\pi r^3$，SA $= 4\\pi r^2$。<br>• <b>棱锥</b>：$V = \\frac{1}{3} \\times \\text{base area} \\times h$。<br><br><b>关键技能</b><br>• 求复合几何体的体积和表面积（例如圆柱体上的半球）。<br>• 已知体积或表面积求缺失的尺寸。<br>• 使用勾股定理求圆锥的斜高。<br><br><b>考试技巧</b><br>公式表上提供了圆锥、球体和棱锥的公式 —— 但要通过练习掌握它们的使用方法。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.4', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A cylinder has radius 4 cm and height 9 cm. Calculate its volume and total surface area.<br><br><b>Solution:</b><br>Volume $= \\pi r^2 h = \\pi \\times 16 \\times 9 = 144\\pi = 452.4\\text{ cm}^3$<br>Total SA $= 2\\pi rh + 2\\pi r^2 = 2\\pi(4)(9) + 2\\pi(16) = 72\\pi + 32\\pi = 104\\pi = 326.7\\text{ cm}^2$<br><br><b>Worked Example 2</b> [4 marks]<br>A cone has base radius 6 cm and vertical height 8 cm. Find the volume and the curved surface area.<br><br><b>Solution:</b><br>Volume $= \\frac{1}{3}\\pi r^2 h = \\frac{1}{3}\\pi \\times 36 \\times 8 = 96\\pi = 301.6\\text{ cm}^3$<br>Slant height: $l = \\sqrt{6^2 + 8^2} = \\sqrt{100} = 10$ cm<br>Curved SA $= \\pi rl = \\pi \\times 6 \\times 10 = 60\\pi = 188.5\\text{ cm}^2$<br><br><b>Worked Example 3</b> [3 marks]<br>A sphere has volume $288\\pi\\text{ cm}^3$. Find its radius and surface area.<br><br><b>Solution:</b><br>$\\frac{4}{3}\\pi r^3 = 288\\pi$<br>$r^3 = 288 \\times \\frac{3}{4} = 216$<br>$r = \\sqrt[3]{216} = 6$ cm<br>SA $= 4\\pi r^2 = 4\\pi \\times 36 = 144\\pi = 452.4\\text{ cm}^2$<br><br><b>Worked Example 4</b> [5 marks]<br>A solid is made from a cylinder (radius 5 cm, height 10 cm) with a hemisphere on top. Find the total volume and total surface area.<br><br><b>Solution:</b><br><b>Volume:</b><br>Cylinder: $\\pi \\times 25 \\times 10 = 250\\pi$<br>Hemisphere: $\\frac{1}{2} \\times \\frac{4}{3}\\pi \\times 125 = \\frac{250\\pi}{3}$<br>Total $= 250\\pi + \\frac{250\\pi}{3} = \\frac{1000\\pi}{3} = 1047\\text{ cm}^3$<br><br><b>Surface area:</b><br>Cylinder curved: $2\\pi \\times 5 \\times 10 = 100\\pi$<br>Base circle: $\\pi \\times 25 = 25\\pi$<br>Hemisphere curved: $2\\pi \\times 25 = 50\\pi$<br>Total $= 100\\pi + 25\\pi + 50\\pi = 175\\pi = 550\\text{ cm}^2$<br><br><b>Worked Example 5</b> [5 marks]<br>A square-based pyramid has base edge 10 cm and vertical height 12 cm. Calculate the volume and the total surface area.<br><br><b>Solution:</b><br>Volume $= \\frac{1}{3} \\times 10^2 \\times 12 = \\frac{1}{3} \\times 1200 = 400\\text{ cm}^3$<br>Slant height of triangular face: from centre of base edge to apex.<br>Half base $= 5$ cm, so $l = \\sqrt{5^2 + 12^2} = \\sqrt{169} = 13$ cm<br>Area of one triangular face $= \\frac{1}{2} \\times 10 \\times 13 = 65\\text{ cm}^2$<br>Total SA $= 10^2 + 4 \\times 65 = 100 + 260 = 360\\text{ cm}^2$<br><br><b>Exam Tip:</b> For compound solids, think about which faces are hidden (e.g. no top circle on a cylinder when a hemisphere sits on it). Formulae for cone, sphere, and pyramid are on the formula sheet.","content_zh":"<b>经典例题 1</b> [3 分]<br>圆柱体半径 4 cm，高 9 cm。计算其体积和总表面积。<br><br><b>解答：</b><br>体积 $= \\pi r^2 h = \\pi \\times 16 \\times 9 = 144\\pi = 452.4\\text{ cm}^3$<br>总表面积 $= 2\\pi rh + 2\\pi r^2 = 72\\pi + 32\\pi = 104\\pi = 326.7\\text{ cm}^2$<br><br><b>经典例题 2</b> [4 分]<br>圆锥体底面半径 6 cm，垂直高度 8 cm。求体积和侧面积。<br><br><b>解答：</b><br>体积 $= \\frac{1}{3}\\pi \\times 36 \\times 8 = 96\\pi = 301.6\\text{ cm}^3$<br>斜高：$l = \\sqrt{6^2 + 8^2} = \\sqrt{100} = 10$ cm<br>侧面积 $= \\pi rl = \\pi \\times 6 \\times 10 = 60\\pi = 188.5\\text{ cm}^2$<br><br><b>经典例题 3</b> [3 分]<br>一个球体的体积为 $288\\pi\\text{ cm}^3$。求其半径和表面积。<br><br><b>解答：</b><br>$\\frac{4}{3}\\pi r^3 = 288\\pi$，$r^3 = 216$，$r = 6$ cm<br>表面积 $= 4\\pi \\times 36 = 144\\pi = 452.4\\text{ cm}^2$<br><br><b>经典例题 4</b> [5 分]<br>一个几何体由一个圆柱体（半径 5 cm，高 10 cm）及其顶部的半球体组成。求其总体积和总表面积。<br><br><b>解答：</b><br><b>体积：</b><br>圆柱体：$250\\pi$，半球体：$\\frac{250\\pi}{3}$<br>总计 $= \\frac{1000\\pi}{3} = 1047\\text{ cm}^3$<br><b>表面积：</b><br>圆柱侧面积 $100\\pi$ + 底面 $25\\pi$ + 半球曲面 $50\\pi = 175\\pi = 550\\text{ cm}^2$<br><br><b>经典例题 5</b> [5 分]<br>正方形底面棱锥，底边 10 cm，垂直高度 12 cm。求体积和总表面积。<br><br><b>解答：</b><br>体积 $= \\frac{1}{3} \\times 100 \\times 12 = 400\\text{ cm}^3$<br>三角面斜高：$l = \\sqrt{5^2 + 12^2} = 13$ cm<br>一个三角面 $= \\frac{1}{2} \\times 10 \\times 13 = 65\\text{ cm}^2$<br>总表面积 $= 100 + 4 \\times 65 = 360\\text{ cm}^2$<br><br><b>考试技巧：</b>对于复合几何体，注意哪些面是被遮挡的（例如：圆柱体顶部放半球时没有顶圆）。圆锥、球体和棱锥的公式在公式表上。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Compound shapes</b> combine two or more basic shapes.<br>• Split the shape into rectangles, triangles, circles, trapeziums, etc.<br>• <b>Addition method</b>: area of whole = sum of parts.<br>• <b>Subtraction method</b>: area of whole shape minus removed sections.<br><br><b>Key Skills</b><br>• Find unknown dimensions from the given information.<br>• Calculate perimeters of compound shapes — only count <b>outer</b> edges.<br>• Solve problems combining 2D and 3D compound shapes.<br><br><b>Exam Tip</b><br>Sketch and label each sub-shape separately. This makes it easier to identify all dimensions.","content_zh":"<b>知识回顾</b><br>• <b>组合图形</b>由两个或多个基本图形组合而成。<br>• 将图形分解为长方形、三角形、圆、梯形等。<br>• <b>相加法</b>：整体面积 = 各部分面积之和。<br>• <b>相减法</b>：整体面积减去移除的部分。<br><br><b>关键技能</b><br>• 根据给定信息找出未知的边长。<br>• 计算组合图形的周长 —— 只计算<b>外部</b>边长。<br>• 解决结合 2D 和 3D 组合图形的问题。<br><br><b>考试技巧</b><br>分别画出每个子图形并标注。这使得识别所有尺寸变得更加容易。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.5', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>An L-shaped room is 10 m by 8 m with a 4 m by 3 m rectangle removed from one corner. Find the area.<br><br><b>Solution:</b><br>Area $= (10 \\times 8) - (4 \\times 3) = 80 - 12 = 68\\text{ m}^2$<br><br><b>Worked Example 2</b> [3 marks]<br>A shape is made from a rectangle 12 cm by 8 cm with a semicircle of diameter 8 cm attached to one end. Find the total area.<br><br><b>Solution:</b><br>Rectangle: $12 \\times 8 = 96\\text{ cm}^2$<br>Semicircle radius $= 4$ cm: $\\frac{1}{2}\\pi \\times 4^2 = 8\\pi = 25.1\\text{ cm}^2$<br>Total area $= 96 + 25.1 = 121.1\\text{ cm}^2$<br><br><b>Worked Example 3</b> [4 marks]<br>A running track consists of a rectangle 100 m by 60 m with semicircles at each end. Calculate the perimeter of the track and the total area enclosed.<br><br><b>Solution:</b><br>Each semicircle has diameter 60 m, so radius $= 30$ m.<br>Perimeter $= 2 \\times 100 + 2 \\times \\frac{1}{2} \\times 2\\pi \\times 30 = 200 + 60\\pi = 200 + 188.5 = 388.5$ m<br>Area $= 100 \\times 60 + \\pi \\times 30^2 = 6000 + 900\\pi = 6000 + 2827.4 = 8827\\text{ m}^2$<br><br><b>Worked Example 4</b> [4 marks]<br>A square has side 20 cm. Four quarter-circles of radius 5 cm are cut from the corners. Find the shaded area remaining and the perimeter of the shaded shape.<br><br><b>Solution:</b><br>Square area $= 20^2 = 400\\text{ cm}^2$<br>Four quarter-circles $= 1$ full circle of radius 5: $\\pi \\times 25 = 78.5\\text{ cm}^2$<br>Shaded area $= 400 - 78.5 = 321.5\\text{ cm}^2$<br>Perimeter: four straight edges of $(20 - 5 - 5) = 10$ cm each, plus four quarter-circle arcs $= 1$ full circumference $= 2\\pi \\times 5 = 31.4$ cm.<br>Total perimeter $= 4 \\times 10 + 31.4 = 71.4$ cm<br><br><b>Exam Tip:</b> For perimeter of compound shapes, trace around the outside carefully. Only count outer edges — internal boundaries are not part of the perimeter.","content_zh":"<b>经典例题 1</b> [3 分]<br>一个 L 形房间长 10 m、宽 8 m，一个角被扣除了 4 m × 3 m 的矩形。求面积。<br><br><b>解答：</b><br>面积 $= (10 \\times 8) - (4 \\times 3) = 80 - 12 = 68\\text{ m}^2$<br><br><b>经典例题 2</b> [3 分]<br>一个图形由一个 12 cm × 8 cm 的矩形和一端附加的直径为 8 cm 的半圆组成。求总面积。<br><br><b>解答：</b><br>矩形：$12 \\times 8 = 96\\text{ cm}^2$<br>半圆半径 $= 4$ cm：$\\frac{1}{2}\\pi \\times 16 = 8\\pi = 25.1\\text{ cm}^2$<br>总面积 $= 96 + 25.1 = 121.1\\text{ cm}^2$<br><br><b>经典例题 3</b> [4 分]<br>跑道由一个 100 m × 60 m 的矩形加两端的半圆组成。计算跑道的周长和总面积。<br><br><b>解答：</b><br>半圆半径 $= 30$ m。<br>周长 $= 200 + 2 \\times \\frac{1}{2} \\times 2\\pi \\times 30 = 200 + 60\\pi = 388.5$ m<br>面积 $= 6000 + \\pi \\times 900 = 6000 + 2827.4 = 8827\\text{ m}^2$<br><br><b>经典例题 4</b> [4 分]<br>正方形边长 20 cm，四个角各挖去一个半径 5 cm 的四分之一圆。求剩余阴影部分的面积和周长。<br><br><b>解答：</b><br>正方形 $= 400\\text{ cm}^2$，四个四分之一圆 $= \\pi \\times 25 = 78.5\\text{ cm}^2$<br>阴影面积 $= 400 - 78.5 = 321.5\\text{ cm}^2$<br>周长：四段直边各 $10$ cm + 四段弧长 $= 2\\pi \\times 5 = 31.4$ cm<br>总周长 $= 40 + 31.4 = 71.4$ cm<br><br><b>考试技巧：</b>求组合图形周长时，沿外围仔细追踪。只计算外部边——内部分界线不属于周长。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.1', 'knowledge', '{"content":"<b>Recap</b><br>• In a right-angled triangle: $a^2 + b^2 = c^2$ where $c$ is the <b>hypotenuse</b> (longest side, opposite the right angle).<br>• To find the hypotenuse: $c = \\sqrt{a^2 + b^2}$.<br>• To find a shorter side: $a = \\sqrt{c^2 - b^2}$.<br><br><b>Key Skills</b><br>• Apply Pythagoras in 2D problems (distances, diagonals).<br>• <b>3D Pythagoras</b> (Extended): find the space diagonal $d = \\sqrt{l^2 + w^2 + h^2}$.<br>• Use Pythagoras to check if a triangle is right-angled: if $a^2 + b^2 = c^2$, yes.<br><br><b>Watch Out!</b><br>The hypotenuse is always opposite the right angle. Always identify it first before applying the theorem.","content_zh":"<b>知识回顾</b><br>• 在直角三角形中：$a^2 + b^2 = c^2$，其中 $c$ 是<b>斜边</b>（最长边，直角的对边）。<br>• 求斜边：$c = \\sqrt{a^2 + b^2}$。<br>• 求较短边：$a = \\sqrt{c^2 - b^2}$。<br><br><b>关键技能</b><br>• 在 2D 问题（距离、对角线）中应用勾股定理。<br>• <b>3D 勾股定理</b>（拓展）：求空间对角线 $d = \\sqrt{l^2 + w^2 + h^2}$。<br>• 使用勾股定理检查三角形是否为直角三角形：如果 $a^2 + b^2 = c^2$，则是。<br><br><b>注意！</b><br>斜边总是直角的对边。在应用定理之前，务必先确定斜边。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the hypotenuse of a right-angled triangle with legs 6 cm and 8 cm.<br><br><b>Solution:</b><br>$c = \\sqrt{6^2 + 8^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$ cm<br><br><b>Worked Example 2</b> [3 marks]<br>A right-angled triangle has hypotenuse 15 cm and one leg 9 cm. Find the other leg.<br><br><b>Solution:</b><br>$a = \\sqrt{15^2 - 9^2} = \\sqrt{225 - 81} = \\sqrt{144} = 12$ cm<br><br><b>Worked Example 3</b> [3 marks]<br>Find the distance between the points $A(1, 3)$ and $B(7, 11)$.<br><br><b>Solution:</b><br>Horizontal distance $= 7 - 1 = 6$<br>Vertical distance $= 11 - 3 = 8$<br>$AB = \\sqrt{6^2 + 8^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>A cuboid has dimensions $3 \\times 4 \\times 12$. Find the length of the space diagonal.<br><br><b>Solution:</b><br>Base diagonal $= \\sqrt{3^2 + 4^2} = \\sqrt{9 + 16} = \\sqrt{25} = 5$<br>Space diagonal $= \\sqrt{5^2 + 12^2} = \\sqrt{25 + 144} = \\sqrt{169} = 13$<br>(Or directly: $d = \\sqrt{3^2 + 4^2 + 12^2} = \\sqrt{169} = 13$)<br><br><b>Exam Tip:</b> The hypotenuse is always the longest side, opposite the right angle. Identify it before substituting into the formula.","content_zh":"<b>经典例题 1</b> [2 分]<br>直角三角形两直角边为 6 cm 和 8 cm，求斜边。<br><br><b>解答：</b><br>$c = \\sqrt{6^2 + 8^2} = \\sqrt{100} = 10$ cm<br><br><b>经典例题 2</b> [3 分]<br>直角三角形斜边 15 cm，一条直角边 9 cm。求另一条直角边。<br><br><b>解答：</b><br>$a = \\sqrt{15^2 - 9^2} = \\sqrt{225 - 81} = \\sqrt{144} = 12$ cm<br><br><b>经典例题 3</b> [3 分]<br>求点 $A(1, 3)$ 和 $B(7, 11)$ 之间的距离。<br><br><b>解答：</b><br>水平距离 $= 6$，垂直距离 $= 8$<br>$AB = \\sqrt{6^2 + 8^2} = \\sqrt{100} = 10$<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>长方体尺寸为 $3 \\times 4 \\times 12$。求空间对角线。<br><br><b>解答：</b><br>底面对角线 $= \\sqrt{9 + 16} = 5$<br>空间对角线 $= \\sqrt{25 + 144} = \\sqrt{169} = 13$<br><br><b>考试技巧：</b>斜边总是最长边，在直角的对面。代入公式前先确定它。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>SOHCAHTOA</b>:<br>&nbsp;&nbsp;$\\sin\\theta = \\frac{\\text{Opposite}}{\\text{Hypotenuse}}$<br>&nbsp;&nbsp;$\\cos\\theta = \\frac{\\text{Adjacent}}{\\text{Hypotenuse}}$<br>&nbsp;&nbsp;$\\tan\\theta = \\frac{\\text{Opposite}}{\\text{Adjacent}}$<br><br><b>Key Skills</b><br>• Find a missing side: identify which ratio involves the known side and the unknown side.<br>• Find a missing angle: use the inverse function ($\\sin^{-1}$, $\\cos^{-1}$, $\\tan^{-1}$).<br>• <b>Angle of elevation</b>: looking UP from horizontal. <b>Angle of depression</b>: looking DOWN from horizontal.<br><br><b>Exam Tip</b><br>Label the sides O, A, H relative to the angle you are using. Then choose the correct ratio.","content_zh":"<b>知识回顾</b><br>• <b>SOHCAHTOA</b>：<br>&nbsp;&nbsp;$\\sin\\theta = \\frac{\\text{对边}}{\\text{斜边}}$<br>&nbsp;&nbsp;$\\cos\\theta = \\frac{\\text{邻边}}{\\text{斜边}}$<br>&nbsp;&nbsp;$\\tan\\theta = \\frac{\\text{对边}}{\\text{邻边}}$<br><br><b>关键技能</b><br>• 求未知边：确定哪个比率涉及已知边和未知边。<br>• 求未知角：使用反函数（$\\sin^{-1}$，$\\cos^{-1}$，$\\tan^{-1}$）。<br>• <b>仰角</b>：从水平线向上看。<b>俯角</b>：从水平线向下看。<br><br><b>考试技巧</b><br>相对于你正在使用的角，将各边标注为 O（对边）、A（邻边）、H（斜边）。然后选择正确的比率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.2', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>In a right-angled triangle, the hypotenuse is 13 cm and one angle is $35°$. Find the side opposite to this angle.<br><br><b>Solution:</b><br>$\\sin 35° = \\frac{\\text{Opp}}{13}$<br>Opp $= 13 \\times \\sin 35° = 13 \\times 0.5736 = 7.46$ cm<br><br><b>Worked Example 2</b> [3 marks]<br>A ladder of length 6 m leans against a wall. The foot of the ladder is 2.5 m from the base of the wall. Find the angle the ladder makes with the ground.<br><br><b>Solution:</b><br>$\\cos\\theta = \\frac{2.5}{6} = 0.4167$<br>$\\theta = \\cos^{-1}(0.4167) = 65.4°$<br><br><b>Worked Example 3</b> [4 marks]<br>From the top of a 25 m cliff, the angle of depression to a boat is $32°$. Find the horizontal distance from the base of the cliff to the boat.<br><br><b>Solution:</b><br>The angle of depression from top = angle of elevation from boat $= 32°$ (alternate angles).<br>$\\tan 32° = \\frac{25}{d}$<br>$d = \\frac{25}{\\tan 32°} = \\frac{25}{0.6249} = 40.0$ m<br><br><b>Worked Example 4</b> [4 marks]<br>A ship sails 15 km due east and then 20 km due north. Find the direct distance from the starting point and the bearing of the ship from its start.<br><br><b>Solution:</b><br>Distance $= \\sqrt{15^2 + 20^2} = \\sqrt{225 + 400} = \\sqrt{625} = 25$ km<br>$\\tan\\theta = \\frac{15}{20} = 0.75$<br>$\\theta = \\tan^{-1}(0.75) = 36.9°$<br>Bearing $= 090° - 36.9° = 053.1°$<br>(Or: from north, angle $= \\tan^{-1}\\frac{15}{20} = 36.9°$ east of north $= 036.9°$... but the ship went east then north, so bearing from start: $\\tan^{-1}\\frac{20}{15}$ from east $= 53.1°$ from east... Bearing $= 90° - 53.1° = 036.9°$.)<br>Bearing from start $= 037°$ (nearest degree).<br><br><b>Exam Tip:</b> Label the sides O, A, H relative to the angle you are working with, then pick the correct ratio (SOH CAH TOA).","content_zh":"<b>经典例题 1</b> [2 分]<br>在直角三角形中，斜边为 13 cm，一个角为 $35°$。求该角的对边。<br><br><b>解答：</b><br>$\\sin 35° = \\frac{\\text{对边}}{13}$<br>对边 $= 13 \\times \\sin 35° = 13 \\times 0.5736 = 7.46$ cm<br><br><b>经典例题 2</b> [3 分]<br>一架 6 m 长的梯子靠在墙上，梯脚距墙底 2.5 m。求梯子与地面的夹角。<br><br><b>解答：</b><br>$\\cos\\theta = \\frac{2.5}{6} = 0.4167$<br>$\\theta = \\cos^{-1}(0.4167) = 65.4°$<br><br><b>经典例题 3</b> [4 分]<br>从 25 m 高的悬崖顶部看一艘船的俯角为 $32°$。求从悬崖底部到船的水平距离。<br><br><b>解答：</b><br>顶部的俯角 $=$ 船的仰角 $= 32°$（内错角）。<br>$\\tan 32° = \\frac{25}{d}$，$d = \\frac{25}{0.6249} = 40.0$ m<br><br><b>经典例题 4</b> [4 分]<br>一艘船先向正东航行 15 km，再向正北航行 20 km。求其与出发点的直线距离和从出发点看的方位角。<br><br><b>解答：</b><br>距离 $= \\sqrt{15^2 + 20^2} = \\sqrt{625} = 25$ km<br>$\\tan\\theta = \\frac{15}{20} = 0.75$，$\\theta = 36.9°$<br>方位角 $= 037°$（最近的整数度）<br><br><b>考试技巧：</b>相对于所用角，将各边标注为 O（对边）、A（邻边）、H（斜边），然后选择正确的比率（SOH CAH TOA）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.3', 'knowledge', '{"content":"<b>Recap</b><br>You must know these exact values (no calculator):<br><br>• $0°$: $\\sin = 0$, $\\cos = 1$, $\\tan = 0$<br>• $30°$: $\\sin = \\frac{1}{2}$, $\\cos = \\frac{\\sqrt{3}}{2}$, $\\tan = \\frac{1}{\\sqrt{3}}$<br>• $45°$: $\\sin = \\frac{\\sqrt{2}}{2}$, $\\cos = \\frac{\\sqrt{2}}{2}$, $\\tan = 1$<br>• $60°$: $\\sin = \\frac{\\sqrt{3}}{2}$, $\\cos = \\frac{1}{2}$, $\\tan = \\sqrt{3}$<br>• $90°$: $\\sin = 1$, $\\cos = 0$, $\\tan$ = undefined<br><br><b>Key Skills</b><br>• Derive values from the 45-45-90 triangle (sides $1, 1, \\sqrt{2}$) and 30-60-90 triangle (sides $1, \\sqrt{3}, 2$).<br>• Use exact values in calculations without a calculator.","content_zh":"<b>知识回顾</b><br>必须记住（不用计算器）：<br>• $\\sin 30° = \\frac{1}{2}$, $\\cos 30° = \\frac{\\sqrt{3}}{2}$, $\\tan 30° = \\frac{1}{\\sqrt{3}}$<br>• $\\sin 45° = \\cos 45° = \\frac{\\sqrt{2}}{2}$, $\\tan 45° = 1$<br>• $\\sin 60° = \\frac{\\sqrt{3}}{2}$, $\\cos 60° = \\frac{1}{2}$, $\\tan 60° = \\sqrt{3}$<br><br>来源：45-45-90 三角形（边 $1, 1, \\sqrt{2}$）和 30-60-90 三角形（边 $1, \\sqrt{3}, 2$）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.3', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Without a calculator, find the exact value of $\\sin 30° + \\cos 60°$.<br><br><b>Solution:</b><br>$\\sin 30° = \\frac{1}{2}$, $\\cos 60° = \\frac{1}{2}$<br>$\\frac{1}{2} + \\frac{1}{2} = 1$<br><br><b>Worked Example 2</b> [3 marks]<br>Without a calculator, find the exact value of $\\frac{\\sin 60°}{\\cos 30°} + \\tan 45°$.<br><br><b>Solution:</b><br>$\\sin 60° = \\frac{\\sqrt{3}}{2}$, $\\cos 30° = \\frac{\\sqrt{3}}{2}$, $\\tan 45° = 1$<br>$\\frac{\\frac{\\sqrt{3}}{2}}{\\frac{\\sqrt{3}}{2}} + 1 = 1 + 1 = 2$<br><br><b>Worked Example 3</b> [3 marks]<br>An equilateral triangle has side length 4 cm. Find the exact area.<br><br><b>Solution:</b><br>Height $= 4\\sin 60° = 4 \\times \\frac{\\sqrt{3}}{2} = 2\\sqrt{3}$ cm<br>Area $= \\frac{1}{2} \\times 4 \\times 2\\sqrt{3} = 4\\sqrt{3}\\text{ cm}^2$<br><br><b>Worked Example 4</b> [3 marks]<br>Show that $\\tan 60° \\times \\cos 60° = \\sin 60°$.<br><br><b>Solution:</b><br>LHS: $\\tan 60° \\times \\cos 60° = \\sqrt{3} \\times \\frac{1}{2} = \\frac{\\sqrt{3}}{2}$<br>RHS: $\\sin 60° = \\frac{\\sqrt{3}}{2}$<br>LHS $=$ RHS, so $\\tan 60° \\times \\cos 60° = \\sin 60°$ ∎<br><br><b>Exam Tip:</b> Memorise the exact values from the 30-60-90 and 45-45-90 triangles. These are not on the formula sheet.","content_zh":"<b>经典例题 1</b> [2 分]<br>不用计算器，求 $\\sin 30° + \\cos 60°$ 的精确值。<br><br><b>解答：</b><br>$\\sin 30° = \\frac{1}{2}$，$\\cos 60° = \\frac{1}{2}$<br>$\\frac{1}{2} + \\frac{1}{2} = 1$<br><br><b>经典例题 2</b> [3 分]<br>不用计算器求 $\\frac{\\sin 60°}{\\cos 30°} + \\tan 45°$ 的精确值。<br><br><b>解答：</b><br>$\\frac{\\frac{\\sqrt{3}}{2}}{\\frac{\\sqrt{3}}{2}} + 1 = 1 + 1 = 2$<br><br><b>经典例题 3</b> [3 分]<br>等边三角形边长 4 cm，求精确面积。<br><br><b>解答：</b><br>高 $= 4\\sin 60° = 2\\sqrt{3}$ cm<br>面积 $= \\frac{1}{2} \\times 4 \\times 2\\sqrt{3} = 4\\sqrt{3}\\text{ cm}^2$<br><br><b>经典例题 4</b> [3 分]<br>证明 $\\tan 60° \\times \\cos 60° = \\sin 60°$。<br><br><b>解答：</b><br>左边：$\\tan 60° \\times \\cos 60° = \\sqrt{3} \\times \\frac{1}{2} = \\frac{\\sqrt{3}}{2}$<br>右边：$\\sin 60° = \\frac{\\sqrt{3}}{2}$<br>左边 $=$ 右边，证毕。<br><br><b>考试技巧：</b>请记住 30-60-90 和 45-45-90 三角形的精确值。这些不在公式表上。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.4', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Sine curve</b> $y = \\sin x$: period $360°$, amplitude 1, passes through origin.<br>• <b>Cosine curve</b> $y = \\cos x$: period $360°$, amplitude 1, starts at $(0, 1)$.<br>• <b>Tangent curve</b> $y = \\tan x$: period $180°$, has vertical asymptotes at $90°, 270°$, etc.<br><br><b>Key Skills</b><br>• Sketch trig graphs for $0° \\leq x \\leq 360°$ (or beyond).<br>• Use symmetry of trig graphs to find multiple solutions: e.g. if $\\sin x = 0.5$, then $x = 30°$ or $x = 150°$.<br>• Solve equations like $\\sin x = k$ in a given range.<br><br><b>Exam Tip</b><br>Sketch the graph to see how many solutions exist in the given range. CAST diagram helps determine signs in each quadrant.","content_zh":"<b>仅限进阶 (Extended Only)</b><br><br><b>知识回顾</b><br>• <b>正弦曲线</b> $y = \\sin x$：周期为 $360°$，振幅为 1，过原点。<br>• <b>余弦曲线</b> $y = \\cos x$：周期为 $360°$，振幅为 1，起始于 $(0, 1)$。<br>• <b>正切曲线</b> $y = \\tan x$：周期为 $180°$，在 $90°, 270°$ 等处有垂直渐近线。<br><br><b>关键技能</b><br>• 绘制 $0° \\leq x \\leq 360°$（或更大范围）的三角函数图像。<br>• 利用三角函数图像的对称性寻找多个解：例如，若 $\\sin x = 0.5$，则 $x = 30°$ 或 $x = 150°$。<br>• 在给定范围内解方程，如 $\\sin x = k$。<br><br><b>考试技巧</b><br>绘制图像以查看在给定范围内存在多少个解。CAST 图有助于确定每个象限中的符号。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.4', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks — Extended]<br>Solve $\\sin x = 0.6$ for $0° \\leq x \\leq 360°$.<br><br><b>Solution:</b><br>$x = \\sin^{-1}(0.6) = 36.87°$<br>Sine is also positive in Q2: $x = 180° - 36.87° = 143.13°$<br>$x = 36.9°$ or $x = 143.1°$ (1 d.p.)<br><br><b>Worked Example 2</b> [3 marks — Extended]<br>Solve $\\cos x = -0.5$ for $0° \\leq x \\leq 360°$.<br><br><b>Solution:</b><br>$\\cos^{-1}(0.5) = 60°$ (reference angle)<br>Cosine is negative in Q2 and Q3:<br>$x = 180° - 60° = 120°$<br>$x = 180° + 60° = 240°$<br>$x = 120°$ or $x = 240°$<br><br><b>Worked Example 3</b> [4 marks — Extended]<br>Solve $\\tan x = -1$ for $0° \\leq x \\leq 360°$.<br><br><b>Solution:</b><br>$\\tan^{-1}(1) = 45°$ (reference angle)<br>Tangent is negative in Q2 and Q4:<br>$x = 180° - 45° = 135°$<br>$x = 360° - 45° = 315°$<br>$x = 135°$ or $x = 315°$<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>Solve $2\\sin x - 1 = 0$ for $0° \\leq x \\leq 360°$.<br><br><b>Solution:</b><br>$2\\sin x = 1$, so $\\sin x = 0.5$<br>$x = \\sin^{-1}(0.5) = 30°$<br>Sine is positive in Q1 and Q2:<br>$x = 30°$ or $x = 180° - 30° = 150°$<br><br><b>Worked Example 5</b> [5 marks — Extended]<br>Solve $3\\cos x + 1 = 0$ for $0° \\leq x \\leq 360°$. Give answers to 1 decimal place.<br><br><b>Solution:</b><br>$3\\cos x = -1$, so $\\cos x = -\\frac{1}{3} = -0.3333$<br>$\\cos^{-1}(0.3333) = 70.53°$ (reference angle)<br>Cosine is negative in Q2 and Q3:<br>$x = 180° - 70.53° = 109.5°$<br>$x = 180° + 70.53° = 250.5°$<br><br><b>Exam Tip:</b> Sketch the graph to count how many solutions exist. Use the CAST diagram: All trig positive in Q1, Sine in Q2, Tangent in Q3, Cosine in Q4.","content_zh":"<b>经典例题 1</b> [3 分 — 进阶]<br>解 $\\sin x = 0.6$，$0° \\leq x \\leq 360°$。<br><br><b>解答：</b><br>$x = \\sin^{-1}(0.6) = 36.87°$<br>正弦在第二象限也为正：$x = 180° - 36.87° = 143.13°$<br>$x = 36.9°$ 或 $x = 143.1°$<br><br><b>经典例题 2</b> [3 分 — 进阶]<br>解 $\\cos x = -0.5$，$0° \\leq x \\leq 360°$。<br><br><b>解答：</b><br>参考角 $\\cos^{-1}(0.5) = 60°$<br>余弦在第二、三象限为负：<br>$x = 180° - 60° = 120°$ 或 $x = 180° + 60° = 240°$<br><br><b>经典例题 3</b> [4 分 — 进阶]<br>解 $\\tan x = -1$，$0° \\leq x \\leq 360°$。<br><br><b>解答：</b><br>参考角 $45°$。正切在第二、四象限为负：<br>$x = 135°$ 或 $x = 315°$<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>解 $2\\sin x - 1 = 0$，$0° \\leq x \\leq 360°$。<br><br><b>解答：</b><br>$\\sin x = 0.5$，$x = 30°$ 或 $x = 150°$<br><br><b>经典例题 5</b> [5 分 — 进阶]<br>解 $3\\cos x + 1 = 0$，$0° \\leq x \\leq 360°$。精确到 1 位小数。<br><br><b>解答：</b><br>$\\cos x = -\\frac{1}{3}$，参考角 $= 70.53°$<br>余弦在第二、三象限为负：<br>$x = 109.5°$ 或 $x = 250.5°$<br><br><b>考试技巧：</b>画图确定解的个数。使用 CAST 图：第一象限全正，第二象限正弦为正，第三象限正切为正，第四象限余弦为正。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.5', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Sine Rule</b><br>$\\frac{a}{\\sin A} = \\frac{b}{\\sin B} = \\frac{c}{\\sin C}$<br>Use when you have: a side and its opposite angle PLUS one other piece.<br><br><b>Cosine Rule</b><br>• Finding a side: $a^2 = b^2 + c^2 - 2bc\\cos A$<br>• Finding an angle: $\\cos A = \\frac{b^2 + c^2 - a^2}{2bc}$<br>Use when you have: SAS (two sides + included angle) or SSS (three sides).<br><br><b>Area Formula</b><br>$A = \\frac{1}{2}ab\\sin C$<br><br><b>Watch Out!</b><br>The <b>ambiguous case</b> of the sine rule: when finding an angle, there may be two possible answers (acute and obtuse). Check if the obtuse answer is valid in context.","content_zh":"<b>仅 Extended</b><br><br><b>正弦定则</b>：$\\frac{a}{\\sin A} = \\frac{b}{\\sin B}$（有一组对边对角时使用）<br><br><b>余弦定则</b>：$a^2 = b^2 + c^2 - 2bc\\cos A$（SAS 或 SSS 时使用）<br>求角：$\\cos A = \\frac{b^2 + c^2 - a^2}{2bc}$<br><br><b>面积</b>：$A = \\frac{1}{2}ab\\sin C$<br><br><b>注意！</b>正弦定则的<b>歧义情况</b>：求角时可能有两个解（锐角和钝角）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.5', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks — Extended]<br>In $\\triangle ABC$: $A = 40°$, $B = 75°$, $a = 10$ cm. Find side $b$.<br><br><b>Solution:</b><br>Using the sine rule: $\\frac{a}{\\sin A} = \\frac{b}{\\sin B}$<br>$\\frac{10}{\\sin 40°} = \\frac{b}{\\sin 75°}$<br>$b = \\frac{10 \\times \\sin 75°}{\\sin 40°} = \\frac{10 \\times 0.9659}{0.6428} = 15.0$ cm<br><br><b>Worked Example 2</b> [4 marks — Extended]<br>In $\\triangle PQR$: $p = 7$ cm, $q = 9$ cm, $r = 5$ cm. Find angle $Q$.<br><br><b>Solution:</b><br>Using the cosine rule to find an angle:<br>$\\cos Q = \\frac{p^2 + r^2 - q^2}{2pr} = \\frac{49 + 25 - 81}{70} = \\frac{-7}{70} = -0.1$<br>$Q = \\cos^{-1}(-0.1) = 95.7°$<br><br><b>Worked Example 3</b> [4 marks — Extended]<br>In $\\triangle ABC$: $b = 11$ cm, $c = 8$ cm, $A = 55°$. Find side $a$.<br><br><b>Solution:</b><br>Using the cosine rule to find a side:<br>$a^2 = b^2 + c^2 - 2bc\\cos A$<br>$a^2 = 121 + 64 - 2(11)(8)\\cos 55°$<br>$a^2 = 185 - 176 \\times 0.5736 = 185 - 100.95 = 84.05$<br>$a = \\sqrt{84.05} = 9.17$ cm<br><br><b>Worked Example 4</b> [4 marks — Extended]<br>In $\\triangle XYZ$: $x = 12$ cm, $y = 9$ cm, $Z = 65°$. Find the area of the triangle.<br><br><b>Solution:</b><br>$A = \\frac{1}{2}xy\\sin Z = \\frac{1}{2} \\times 12 \\times 9 \\times \\sin 65°$<br>$= 54 \\times 0.9063 = 48.9\\text{ cm}^2$<br><br><b>Worked Example 5</b> [5 marks — Extended]<br>Two ships leave a port at the same time. Ship A sails 20 km on a bearing of $060°$ and ship B sails 15 km on a bearing of $130°$. Find the distance between the two ships.<br><br><b>Solution:</b><br>Angle at the port between the two paths $= 130° - 60° = 70°$<br>Using the cosine rule with sides 20 and 15, included angle $70°$:<br>$d^2 = 20^2 + 15^2 - 2(20)(15)\\cos 70°$<br>$d^2 = 400 + 225 - 600 \\times 0.3420 = 625 - 205.2 = 419.8$<br>$d = \\sqrt{419.8} = 20.5$ km<br><br><b>Exam Tip:</b> Choose sine rule when you have a side-angle pair; choose cosine rule for SAS or SSS. Watch for the ambiguous case with the sine rule when finding angles.","content_zh":"<b>经典例题 1</b> [3 分 — 进阶]<br>在 $\\triangle ABC$ 中：$A = 40°$，$B = 75°$，$a = 10$ cm。求边 $b$。<br><br><b>解答：</b><br>正弦定则：$\\frac{10}{\\sin 40°} = \\frac{b}{\\sin 75°}$<br>$b = \\frac{10 \\times 0.9659}{0.6428} = 15.0$ cm<br><br><b>经典例题 2</b> [4 分 — 进阶]<br>在 $\\triangle PQR$ 中：$p = 7$，$q = 9$，$r = 5$。求角 $Q$。<br><br><b>解答：</b><br>$\\cos Q = \\frac{49 + 25 - 81}{70} = \\frac{-7}{70} = -0.1$<br>$Q = \\cos^{-1}(-0.1) = 95.7°$<br><br><b>经典例题 3</b> [4 分 — 进阶]<br>在 $\\triangle ABC$ 中：$b = 11$ cm，$c = 8$ cm，$A = 55°$。求边 $a$。<br><br><b>解答：</b><br>$a^2 = 121 + 64 - 2(11)(8)\\cos 55° = 185 - 100.95 = 84.05$<br>$a = \\sqrt{84.05} = 9.17$ cm<br><br><b>经典例题 4</b> [4 分 — 进阶]<br>在 $\\triangle XYZ$ 中：$x = 12$ cm，$y = 9$ cm，$Z = 65°$。求三角形面积。<br><br><b>解答：</b><br>$A = \\frac{1}{2} \\times 12 \\times 9 \\times \\sin 65° = 54 \\times 0.9063 = 48.9\\text{ cm}^2$<br><br><b>经典例题 5</b> [5 分 — 进阶]<br>两艘船同时从港口出发。A 船以 $060°$ 方位角航行 20 km，B 船以 $130°$ 方位角航行 15 km。求两船之间的距离。<br><br><b>解答：</b><br>港口处夹角 $= 130° - 60° = 70°$<br>$d^2 = 20^2 + 15^2 - 2(20)(15)\\cos 70° = 625 - 205.2 = 419.8$<br>$d = \\sqrt{419.8} = 20.5$ km<br><br><b>考试技巧：</b>有对边对角时用正弦定则；SAS 或 SSS 时用余弦定则。注意正弦定则求角时可能存在歧义情况。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.6', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• In 3D problems, identify <b>right-angled triangles</b> within the solid.<br>• Apply <b>Pythagoras</b> and <b>SOHCAHTOA</b> to these 2D cross-sections.<br>• Common 3D shapes: cuboid, pyramid, wedge, cone.<br><br><b>Key Skills</b><br>• Find the <b>angle between a line and a plane</b>: drop a perpendicular from the point to the plane, identify the right triangle.<br>• Find the <b>angle between two planes</b>: find the line where they intersect, then draw perpendiculars in each plane to this line.<br>• Usually requires <b>two steps</b>: first find a length (using Pythagoras), then an angle (using trig).<br><br><b>Exam Tip</b><br>Draw a clear 2D right triangle extracted from the 3D shape. Label all known and unknown sides/angles.","content_zh":"<b>仅限进阶 (Extended Only)</b><br><br><b>知识回顾</b><br>• 在 3D 问题中，识别立体图形内部的<b>直角三角形</b>。<br>• 将<b>勾股定理</b>（Pythagoras）和 <b>SOHCAHTOA</b> 应用于这些 2D 截面。<br>• 常见的 3D 图形：长方体、棱锥、楔形体、圆锥。<br><br><b>关键技能</b><br>• 求<b>直线与平面之间的夹角</b>：从点向平面作垂线，识别直角三角形。<br>• 求<b>两个平面之间的夹角</b>：找到它们的交线，然后在每个平面内画出垂直于该交线的垂线。<br>• 通常需要<b>两步</b>：首先求长度（利用勾股定理），然后求角度（利用三角函数）。<br><br><b>考试技巧</b><br>画出从 3D 图形中提取的清晰 2D 直角三角形。标记所有已知和未知的边/角。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.6', 'examples', '{"content":"<b>Worked Example 1</b> [4 marks — Extended]<br>A cuboid has dimensions $8 \\times 6 \\times 4$ cm. Find the angle between the space diagonal $AG$ and the base $ABCD$.<br><br><b>Solution:</b><br>Step 1: Base diagonal $AC = \\sqrt{8^2 + 6^2} = \\sqrt{100} = 10$ cm<br>Step 2: Right triangle with base $AC = 10$ and height $CG = 4$:<br>$\\tan\\theta = \\frac{4}{10} = 0.4$<br>$\\theta = \\tan^{-1}(0.4) = 21.8°$<br><br><b>Worked Example 2</b> [4 marks — Extended]<br>A square-based pyramid has base edge 10 cm and vertical height 12 cm. Find the angle between a slant edge and the base.<br><br><b>Solution:</b><br>Step 1: Half the base diagonal $= \\frac{1}{2}\\sqrt{10^2 + 10^2} = \\frac{1}{2}\\sqrt{200} = \\frac{10\\sqrt{2}}{2} = 5\\sqrt{2} = 7.071$ cm<br>Step 2: Right triangle with base $= 5\\sqrt{2}$ and height $= 12$:<br>$\\tan\\theta = \\frac{12}{5\\sqrt{2}} = \\frac{12}{7.071} = 1.697$<br>$\\theta = \\tan^{-1}(1.697) = 59.5°$<br><br><b>Worked Example 3</b> [5 marks — Extended]<br>A cone has base radius 5 cm and slant height 13 cm. Find (a) the vertical height, (b) the angle between the slant height and the base.<br><br><b>Solution:</b><br>(a) $h = \\sqrt{13^2 - 5^2} = \\sqrt{169 - 25} = \\sqrt{144} = 12$ cm<br>(b) $\\cos\\theta = \\frac{5}{13}$, so $\\theta = \\cos^{-1}(0.3846) = 67.4°$<br>(Or: $\\tan\\theta = \\frac{12}{5} = 2.4$, $\\theta = 67.4°$)<br><br><b>Worked Example 4</b> [5 marks — Extended]<br>A cuboid $ABCDEFGH$ has $AB = 12$ cm, $BC = 5$ cm, $CG = 8$ cm. $M$ is the midpoint of $EH$. Find the length $BM$ and the angle $BM$ makes with the base $ABCD$.<br><br><b>Solution:</b><br>Step 1: $M$ is the midpoint of $EH$, so the projection of $M$ onto the base is the midpoint $N$ of $AD$.<br>$BN$: $B$ to $N$ across the base. $N$ is at $(0, 2.5)$ if $B = (12, 0)$ (taking $A$ as origin, $AB$ along $x$, $AD$ along $y$).<br>$BN = \\sqrt{12^2 + 2.5^2} = \\sqrt{144 + 6.25} = \\sqrt{150.25} = 12.26$ cm<br>Step 2: $BM$ is the hypotenuse of the right triangle with base $BN = 12.26$ and height $= CG = 8$:<br>$BM = \\sqrt{12.26^2 + 8^2} = \\sqrt{150.25 + 64} = \\sqrt{214.25} = 14.6$ cm<br>Step 3: $\\tan\\theta = \\frac{8}{12.26} = 0.6525$<br>$\\theta = \\tan^{-1}(0.6525) = 33.1°$<br><br><b>Worked Example 5</b> [6 marks — Extended]<br>A vertical pole $OP$ of height $h$ stands at point $O$ on level ground. Point $A$ is due north of $O$ and point $B$ is due east of $O$. From $A$, the angle of elevation of $P$ is $35°$. From $B$, the angle of elevation of $P$ is $28°$. $AB = 50$ m. Find $h$.<br><br><b>Solution:</b><br>From $A$: $\\tan 35° = \\frac{h}{OA}$, so $OA = \\frac{h}{\\tan 35°}$<br>From $B$: $\\tan 28° = \\frac{h}{OB}$, so $OB = \\frac{h}{\\tan 28°}$<br>$A$ is north, $B$ is east, so $\\angle AOB = 90°$ and $AB^2 = OA^2 + OB^2$:<br>$50^2 = \\frac{h^2}{\\tan^2 35°} + \\frac{h^2}{\\tan^2 28°}$<br>$2500 = h^2\\left(\\frac{1}{0.7002^2} + \\frac{1}{0.5317^2}\\right) = h^2(2.040 + 3.537) = 5.577h^2$<br>$h^2 = \\frac{2500}{5.577} = 448.3$<br>$h = \\sqrt{448.3} = 21.2$ m<br><br><b>Exam Tip:</b> In 3D problems, always extract a clear 2D right triangle from the solid. Draw it separately and label all known sides and angles.","content_zh":"<b>经典例题 1</b> [4 分 — 进阶]<br>长方体尺寸 $8 \\times 6 \\times 4$ cm。求空间对角线 $AG$ 与底面 $ABCD$ 的夹角。<br><br><b>解答：</b><br>底面对角线 $AC = \\sqrt{64 + 36} = 10$ cm<br>$\\tan\\theta = \\frac{4}{10} = 0.4$，$\\theta = 21.8°$<br><br><b>经典例题 2</b> [4 分 — 进阶]<br>正方形底面棱锥底边 10 cm，垂直高度 12 cm。求斜棱与底面的夹角。<br><br><b>解答：</b><br>底面半对角线 $= \\frac{10\\sqrt{2}}{2} = 5\\sqrt{2} = 7.071$ cm<br>$\\tan\\theta = \\frac{12}{5\\sqrt{2}} = 1.697$，$\\theta = 59.5°$<br><br><b>经典例题 3</b> [5 分 — 进阶]<br>圆锥底面半径 5 cm，斜高 13 cm。求 (a) 垂直高度，(b) 斜高与底面的夹角。<br><br><b>解答：</b><br>(a) $h = \\sqrt{169 - 25} = 12$ cm<br>(b) $\\tan\\theta = \\frac{12}{5} = 2.4$，$\\theta = 67.4°$<br><br><b>经典例题 4</b> [5 分 — 进阶]<br>长方体 $AB = 12$ cm，$BC = 5$ cm，$CG = 8$ cm。$M$ 是 $EH$ 的中点。求 $BM$ 的长度及 $BM$ 与底面的夹角。<br><br><b>解答：</b><br>$M$ 在底面的投影 $N$ 是 $AD$ 的中点。<br>$BN = \\sqrt{12^2 + 2.5^2} = \\sqrt{150.25} = 12.26$ cm<br>$BM = \\sqrt{12.26^2 + 8^2} = \\sqrt{214.25} = 14.6$ cm<br>$\\tan\\theta = \\frac{8}{12.26}$，$\\theta = 33.1°$<br><br><b>经典例题 5</b> [6 分 — 进阶]<br>竖直杆 $OP$（高 $h$）立于水平地面上的 $O$ 点。$A$ 在 $O$ 的正北，$B$ 在 $O$ 的正东。从 $A$ 看 $P$ 的仰角为 $35°$，从 $B$ 看 $P$ 的仰角为 $28°$。$AB = 50$ m，求 $h$。<br><br><b>解答：</b><br>$OA = \\frac{h}{\\tan 35°}$，$OB = \\frac{h}{\\tan 28°}$<br>$\\angle AOB = 90°$，$50^2 = OA^2 + OB^2$<br>$2500 = h^2(\\frac{1}{\\tan^2 35°} + \\frac{1}{\\tan^2 28°}) = 5.577h^2$<br>$h = \\sqrt{\\frac{2500}{5.577}} = 21.2$ m<br><br><b>考试技巧：</b>在 3D 问题中，始终从立体图形中提取清晰的 2D 直角三角形，单独画出并标注所有已知的边和角。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.1', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>vector</b> has magnitude (size) and direction. Written as $\\vec{AB}$, $\\mathbf{a}$, or $\\binom{x}{y}$.<br>• A <b>scalar</b> has magnitude only (just a number).<br>• <b>Column vector</b>: $\\binom{3}{-2}$ means 3 right and 2 down.<br>• <b>Addition</b>: $\\binom{a}{b} + \\binom{c}{d} = \\binom{a+c}{b+d}$.<br>• <b>Scalar multiplication</b>: $k\\binom{a}{b} = \\binom{ka}{kb}$.<br>• <b>Magnitude</b>: $|\\mathbf{a}| = \\sqrt{x^2 + y^2}$.<br>• <b>Parallel vectors</b>: one is a scalar multiple of the other.<br>• $-\\mathbf{a}$ reverses direction. $\\vec{BA} = -\\vec{AB}$.<br><br><b>Higher Only</b><br>• <b>Vector geometry proofs</b>: express vectors in terms of $\\mathbf{a}$ and $\\mathbf{b}$.<br>• To prove points are collinear, show one vector is a scalar multiple of another.<br>• Midpoint: $\\vec{OM} = \\frac{1}{2}(\\vec{OA} + \\vec{OB})$.<br><br><b>Exam Tip</b><br>When finding a route, go via known points: $\\vec{AC} = \\vec{AB} + \\vec{BC}$.","content_zh":"<b>知识回顾</b><br>• <b>向量</b>有大小和方向。列向量 $\\binom{3}{-2}$：右 3 下 2。<br>• 加法：$\\binom{a}{b} + \\binom{c}{d} = \\binom{a+c}{b+d}$。<br>• 标量乘法：$k\\binom{a}{b} = \\binom{ka}{kb}$。模：$|\\mathbf{a}| = \\sqrt{x^2+y^2}$。<br>• 平行向量：一个是另一个的标量倍。$-\\mathbf{a}$ 反向。<br><br><b>仅 Higher</b><br>• 向量几何证明：用 $\\mathbf{a}, \\mathbf{b}$ 表示向量。<br>• 共线：一个向量是另一个的标量倍。<br><br><b>考试技巧</b>经过已知点找路径：$\\vec{AC} = \\vec{AB} + \\vec{BC}$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>$\\mathbf{a} = \\binom{3}{-1}$ and $\\mathbf{b} = \\binom{-2}{4}$. Find $2\\mathbf{a} + \\mathbf{b}$.<br><br><b>Solution:</b><br>$2\\mathbf{a} + \\mathbf{b} = \\binom{6}{-2} + \\binom{-2}{4} = \\binom{4}{2}$<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>$\\vec{OA} = \\mathbf{a}$, $\\vec{OB} = \\mathbf{b}$. $M$ is the midpoint of $AB$. Find $\\vec{OM}$.<br><br><b>Solution:</b><br>$\\vec{AB} = \\mathbf{b} - \\mathbf{a}$<br>$\\vec{AM} = \\frac{1}{2}\\vec{AB} = \\frac{1}{2}(\\mathbf{b} - \\mathbf{a})$<br>$\\vec{OM} = \\vec{OA} + \\vec{AM} = \\mathbf{a} + \\frac{1}{2}(\\mathbf{b} - \\mathbf{a}) = \\frac{1}{2}\\mathbf{a} + \\frac{1}{2}\\mathbf{b} = \\frac{1}{2}(\\mathbf{a} + \\mathbf{b})$","content_zh":"<b>经典例题 1</b> [2 分]<br>$\\mathbf{a} = \\binom{3}{-1}$，$\\mathbf{b} = \\binom{-2}{4}$。求 $2\\mathbf{a} + \\mathbf{b}$。<br><br><b>解答：</b>$\\binom{4}{2}$<br><br><b>经典例题 2</b>（Higher）[4 分]<br>$\\vec{OA} = \\mathbf{a}$，$\\vec{OB} = \\mathbf{b}$，$M$ 为 $AB$ 中点。求 $\\vec{OM}$。<br><br><b>解答：</b>$\\vec{OM} = \\frac{1}{2}(\\mathbf{a} + \\mathbf{b})$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Translation</b>: slide by vector $\\binom{a}{b}$. No change in size, shape, or orientation.<br>• <b>Reflection</b>: flip in a mirror line. Describe with the <b>equation of the line</b>.<br>• <b>Rotation</b>: turn about a centre. Describe with <b>centre, angle, direction</b> (clockwise/anticlockwise).<br>• <b>Enlargement</b>: resize from a centre. Describe with <b>centre, scale factor</b>.<br>&nbsp;&nbsp;$k > 1$: bigger. $0 < k < 1$: smaller. $k < 0$: inverted (Higher).<br><br><b>Key Skills</b><br>• Perform each transformation on a shape on a coordinate grid.<br>• <b>Describe</b> a given transformation fully (must include all required details).<br><br><b>Watch Out!</b><br>\"Describe fully\" means you need ALL the details. For rotation: centre + angle + direction. For enlargement: centre + scale factor. Missing any one loses marks.","content_zh":"<b>知识回顾</b><br>• <b>平移</b>：按向量 $\\binom{a}{b}$ 滑动。大小、形状或方向没有变化。<br>• <b>反射</b>：在镜像线中翻转。用<b>直线方程</b>描述。<br>• <b>旋转</b>：绕中心转动。用<b>中心、角度、方向</b>（顺时针/逆时针）描述。<br>• <b>位似（放大/缩小）</b>：从中心调整大小。用<b>中心、比例因子</b>描述。<br>&nbsp;&nbsp;$k > 1$：变大。$0 < k < 1$：变小。$k < 0$：倒置（仅 Higher）。<br><br><b>关键技能</b><br>• 在坐标网格上的图形上执行每种变换。<br>• <b>完整描述</b>给定的变换（必须包括所有必需的细节）。<br><br><b>注意！</b><br>\"Describe fully\"（完整描述）意味着你需要所有的细节。对于旋转：中心 + 角度 + 方向。对于位似：中心 + 比例因子。遗漏任何一项都会扣分。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.2', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Triangle $A$ has vertices $(1,1)$, $(3,1)$, $(1,4)$. It is rotated $90°$ clockwise about the origin. Find the image vertices.<br><br><b>Solution:</b><br>$90°$ clockwise: $(x, y) \\rightarrow (y, -x)$<br>$(1,1) \\rightarrow (1,-1)$, $(3,1) \\rightarrow (1,-3)$, $(1,4) \\rightarrow (4,-1)$<br><br><b>Worked Example 2</b> [3 marks]<br>Describe fully the single transformation that maps triangle $P$ at $(2,3), (6,3), (6,5)$ to triangle $Q$ at $(4,6), (12,6), (12,10)$.<br><br><b>Solution:</b><br><b>Enlargement</b>, scale factor <b>2</b>, centre <b>$(0, 0)$</b>.<br>(Each coordinate is doubled, so centre is origin.)","content_zh":"<b>经典例题 1</b> [3 分]<br>三角形顶点 $(1,1), (3,1), (1,4)$，绕原点顺时针旋转 $90°$。求像。<br><br><b>解答：</b>$(x,y) \\rightarrow (y,-x)$：$(1,-1), (1,-3), (4,-1)$<br><br><b>经典例题 2</b> [3 分]<br>描述变换：$P(2,3),(6,3),(6,5)$ → $Q(4,6),(12,6),(12,10)$。<br><br><b>解答：</b>以原点为中心、缩放因子 2 的<b>放大</b>。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Bar chart</b>: bars for categorical data. Gaps between bars.<br>• <b>Pictogram</b>: pictures represent data. Include a key.<br>• <b>Pie chart</b>: angles proportional to frequency. Total = $360°$.<br>• <b>Line graph</b>: for time series data. Plot points and join.<br>• <b>Stem-and-leaf diagram</b>: ordered raw data display. Must include a key.<br>• <b>Frequency polygon</b>: plot midpoints of classes, join with straight lines.<br>• <b>Scatter diagram</b>: show relationship between two variables. Describe <b>correlation</b> (positive, negative, none).<br><br><b>Higher Only</b><br>• <b>Histogram</b>: frequency density $= \\frac{\\text{frequency}}{\\text{class width}}$. <b>No gaps</b> between bars.<br>• <b>Cumulative frequency</b>: running total plotted at upper class boundary. S-shaped curve.<br>• <b>Box plot</b> (box-and-whisker): min, LQ, median, UQ, max.<br><br><b>Exam Tip</b><br>In histograms, the <b>area</b> of each bar represents frequency, not the height.","content_zh":"<b>知识回顾</b><br>• <b>柱状图</b>：用于分类数据的条形。条形之间有间隔。<br>• <b>象形图</b>：图片代表数据。包括图例（Key）。<br>• <b>饼图</b>：角度与频率成正比。总计 $= 360°$。<br>• <b>折线图</b>：用于时间序列数据。描点并连接。<br>• <b>茎叶图</b>：有序原始数据显示。必须包括图例（Key）。<br>• <b>频率多边形</b>：描出各组的中点，用直线连接。<br>• <b>散点图</b>：显示两个变量之间的关系。描述<b>相关性</b>（正相关、负相关、无相关）。<br><br><b>仅 Higher</b><br>• <b>直方图</b>：频率密度 $= \\frac{\\text{frequency}}{\\text{class width}}$。条形之间<b>没有间隔</b>。<br>• <b>累积频率</b>：在组上限描出的累计总量。S 形曲线。<br>• <b>箱线图</b>（盒须图）：最小值、下四分位数（LQ）、中位数、上四分位数（UQ）、最大值。<br><br><b>考试技巧</b><br>在直方图中，每个条形的<b>面积</b>代表频率，而不是高度。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>40 students took a test. Draw a pie chart angle for the 15 who scored A.<br><br><b>Solution:</b><br>Angle $= \\frac{15}{40} \\times 360° = 135°$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>A grouped frequency table has class $10 \\leq x < 25$ with frequency 30. Find the frequency density and bar height for the histogram.<br><br><b>Solution:</b><br>Class width $= 25 - 10 = 15$<br>Frequency density $= \\frac{30}{15} = 2$<br>The bar has height 2 and width from 10 to 25.","content_zh":"<b>经典例题 1</b> [2 分]<br>40 名学生中 15 人得 A，画饼图角度。<br><b>解答：</b>$\\frac{15}{40} \\times 360° = 135°$<br><br><b>经典例题 2</b>（Higher）[3 分]<br>分组频率表：$10 \\leq x < 25$，频率 30。求频率密度。<br><b>解答：</b>组距 15，频率密度 $= \\frac{30}{15} = 2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Mean</b> $= \\frac{\\text{sum of values}}{\\text{number of values}}$. For grouped data: $\\bar{x} = \\frac{\\sum fx}{\\sum f}$ (use midpoints).<br>• <b>Median</b>: middle value when data is ordered. Position: $\\frac{n+1}{2}$.<br>• <b>Mode</b>: most common value. Can have no mode or multiple modes.<br>• <b>Range</b> $=$ largest $-$ smallest.<br><br><b>Higher Only</b><br>• <b>Interquartile range (IQR)</b> $= Q_3 - Q_1$. Measures the spread of the middle 50%.<br>• From cumulative frequency: median at $\\frac{n}{2}$, $Q_1$ at $\\frac{n}{4}$, $Q_3$ at $\\frac{3n}{4}$.<br>• Compare distributions using an average (mean or median) AND a measure of spread (range or IQR).<br><br><b>Exam Tip</b><br>For grouped data, the mean uses midpoints so it is an <b>estimate</b>. Say \"estimated mean\".","content_zh":"<b>知识回顾</b><br>• <b>平均数 (Mean)</b> $= \\frac{\\text{sum of values}}{\\text{number of values}}$。对于分组数据：$\\bar{x} = \\frac{\\sum fx}{\\sum f}$（使用组中值）。<br>• <b>中位数 (Median)</b>：数据排序后的中间值。位置：$\\frac{n+1}{2}$。<br>• <b>众数 (Mode)</b>：最常见的值。可以没有众数或有多个众数。<br>• <b>极差 (Range)</b> $=$ largest $-$ smallest。<br><br><b>仅 Higher</b><br>• <b>四分位距 (IQR)</b> $= Q_3 - Q_1$。衡量中间 50% 数据的离散程度。<br>• 根据累积频数：中位数位于 $\\frac{n}{2}$，$Q_1$ 位于 $\\frac{n}{4}$，$Q_3$ 位于 $\\frac{3n}{4}$。<br>• 使用平均数（平均值或中位数）以及离散程度（极差或 IQR）来比较分布。<br><br><b>考试技巧</b><br>对于分组数据，平均数使用组中值计算，因此它是一个<b>估计值</b>。请表述为\"估计平均数 (estimated mean)\"。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.2', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Five students scored: 45, 62, 58, 71, 54. Find the mean, median, and range.<br><br><b>Solution:</b><br>Mean $= \\frac{45+62+58+71+54}{5} = \\frac{290}{5} = 58$<br>Ordered: 45, 54, 58, 62, 71. Median $= 58$<br>Range $= 71 - 45 = 26$<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>From a cumulative frequency graph, $n = 80$. Read off the median and IQR.<br><br><b>Solution:</b><br>Median at $\\frac{80}{2} = 40$th value. Read across: median $= 52$.<br>$Q_1$ at 20th value $= 43$. $Q_3$ at 60th value $= 64$.<br>IQR $= 64 - 43 = 21$.","content_zh":"<b>经典例题 1</b> [3 分]<br>五名学生的得分为：45, 62, 58, 71, 54。求平均数、中位数和极差。<br><br><b>解答：</b><br>平均数 $= \\frac{45+62+58+71+54}{5} = \\frac{290}{5} = 58$<br>排序后：45, 54, 58, 62, 71。中位数 $= 58$<br>极差 $= 71 - 45 = 26$<br><br><b>经典例题 2</b>（Higher）[4 分]<br>根据累积频数图，$n = 80$。读出中位数和四分位距（IQR）。<br><br><b>解答：</b><br>中位数位于第 $\\frac{80}{2} = 40$ 个数值处。水平读取：中位数 $= 52$。<br>$Q_1$ 位于第 20 个数值处 $= 43$。$Q_3$ 位于第 60 个数值处 $= 64$。<br>IQR $= 64 - 43 = 21$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.3', 'knowledge', '{"content":"<b>Recap</b><br>• $P(\\text{event}) = \\frac{\\text{favourable outcomes}}{\\text{total outcomes}}$. Always $0 \\leq P \\leq 1$.<br>• $P(\\text{not } A) = 1 - P(A)$.<br>• <b>Sample space</b>: list of all outcomes. Use tables or lists for combined events.<br>• <b>Relative frequency</b> $= \\frac{\\text{number of times event occurs}}{\\text{total trials}}$. Better estimate with more trials.<br><br><b>Key Skills</b><br>• <b>Tree diagrams</b>: multiply along branches (AND), add between branches (OR).<br>• <b>Independent events</b>: $P(A \\text{ and } B) = P(A) \\times P(B)$.<br>• <b>Mutually exclusive</b>: $P(A \\text{ or } B) = P(A) + P(B)$.<br><br><b>Higher Only</b><br>• <b>Conditional probability</b>: $P(A | B) = \\frac{P(A \\cap B)}{P(B)}$.<br>• <b>Without replacement</b>: probabilities change on second pick.<br>• <b>Venn diagrams</b>: $P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$.<br><br><b>Watch Out!</b><br>\"At least one\" is easiest solved as $1 - P(\\text{none})$.","content_zh":"<b>知识回顾</b><br>• $P(\\text{事件}) = \\frac{\\text{有利结果}}{\\text{总结果}}$。概率值始终满足 $0 \\leq P \\leq 1$。<br>• $P(\\text{非 } A) = 1 - P(A)$。<br>• <b>样本空间 (Sample space)</b>：列出所有可能结果的完整清单。对于组合事件，建议使用表格或列表进行系统列举。<br>• <b>相对频率 (Relative frequency)</b> $= \\frac{\\text{事件发生的次数}}{\\text{总试验次数}}$。随着试验次数的增加，相对频率对理论概率的估算会越发准确。<br><br><b>关键技能</b><br>• <b>树状图 (Tree diagrams)</b>：沿路径的分支相乘（表示\"且\" AND），不同路径的分支结果相加（表示\"或\" OR）。<br>• <b>独立事件 (Independent events)</b>：$P(A \\text{ 且 } B) = P(A) \\times P(B)$。<br>• <b>互斥事件 (Mutually exclusive)</b>：$P(A \\text{ 或 } B) = P(A) + P(B)$。<br><br><b>仅 Higher</b><br>• <b>条件概率 (Conditional probability)</b>：$P(A | B) = \\frac{P(A \\cap B)}{P(B)}$。<br>• <b>不放回抽样 (Without replacement)</b>：在第二次抽取时，由于总数和符合条件数通常都会减少，概率会随之改变。<br>• <b>韦恩图 (Venn diagrams)</b>：$P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$。<br><br><b>注意！</b><br>解决\"至少一个 (At least one)\"类问题时，最简便的方法通常是使用补集计算：$1 - P(\\text{一个都没有})$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.3', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A bag has 5 red and 3 blue balls. One is picked at random, not replaced, then another is picked. Find the probability both are red.<br><br><b>Solution:</b><br>$P(\\text{1st red}) = \\frac{5}{8}$<br>$P(\\text{2nd red} | \\text{1st red}) = \\frac{4}{7}$<br>$P(\\text{both red}) = \\frac{5}{8} \\times \\frac{4}{7} = \\frac{20}{56} = \\frac{5}{14}$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>$P(A) = 0.6$, $P(B) = 0.3$, $P(A \\cap B) = 0.15$. Find $P(A \\cup B)$ and determine if $A$ and $B$ are independent.<br><br><b>Solution:</b><br>$P(A \\cup B) = 0.6 + 0.3 - 0.15 = 0.75$<br>Check: $P(A) \\times P(B) = 0.18 \\neq 0.15$, so NOT independent.<br><br><b>Exam Tip:</b> Independent ⟺ $P(A \\cap B) = P(A) \\times P(B)$.","content_zh":"<b>知识回顾</b><br>• $P(\\text{event}) = \\frac{\\text{favourable outcomes}}{\\text{total outcomes}}$。始终满足 $0 \\leq P \\leq 1$。<br>• $P(\\text{not } A) = 1 - P(A)$。<br>• <b>样本空间 (Sample space)</b>：列出所有结果的清单。对于复合事件，使用表格或列表。<br>• <b>相对频数 (Relative frequency)</b> $= \\frac{\\text{number of times event occurs}}{\\text{total trials}}$。试验次数越多，估计效果越好。<br><br><b>关键技能</b><br>• <b>树状图</b>：沿分叉相乘（AND），分叉间相加（OR）。<br>• <b>独立事件</b>：$P(A \\text{ and } B) = P(A) \\times P(B)$。<br>• <b>互斥事件</b>：$P(A \\text{ or } B) = P(A) + P(B)$。<br><br><b>仅 Higher</b><br>• <b>条件概率</b>：$P(A | B) = \\frac{P(A \\cap B)}{P(B)}$。<br>• <b>不放回 (Without replacement)</b>：第二次抽取的概率会发生变化。<br>• <b>维恩图 (Venn diagrams)</b>：$P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$。<br><br><b>注意！</b><br>\"至少一个\"最容易通过 $1 - P(\\text{none})$ 来解答。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
